from __future__ import annotations

from pathlib import Path
import py_compile

ROOT_DIR = Path(r"C:\missio")

FILES = {'backend/app/core/tokens.py': 'from __future__ import annotations\n\nfrom dataclasses import dataclass\nfrom datetime import datetime, timedelta, timezone\nfrom typing import Any\n\nfrom jose import JWTError, jwt\n\nfrom app.core.config import settings\nfrom app.core.roles import is_valid_role\n\n\nALGORITHM = "HS256"\nTOKEN_TYPE_ACCESS = "access"\nTOKEN_ISSUER = "missio"\n\n\nclass InvalidTokenError(ValueError):\n    """Raised when a JWT token is invalid or expired."""\n\n\n@dataclass(frozen=True)\nclass AccessTokenPayload:\n    """Validated access token payload."""\n\n    subject: str\n    role: str\n    business_id: int | None\n    expires_at: datetime\n    issued_at: datetime\n\n\ndef get_utc_now() -> datetime:\n    """Return current UTC datetime."""\n\n    return datetime.now(timezone.utc)\n\n\ndef create_access_token(\n    subject: str,\n    role: str,\n    business_id: int | None = None,\n    expires_delta: timedelta | None = None,\n) -> str:\n    """Create a signed JWT access token."""\n\n    if not subject:\n        raise ValueError("Token subject boş olamaz.")\n\n    if not is_valid_role(role):\n        raise ValueError("Geçersiz kullanıcı rolü.")\n\n    now = get_utc_now()\n\n    if expires_delta is None:\n        expires_delta = timedelta(minutes=settings.access_token_expire_minutes)\n\n    expires_at = now + expires_delta\n\n    claims: dict[str, Any] = {\n        "sub": subject,\n        "role": role,\n        "business_id": business_id,\n        "type": TOKEN_TYPE_ACCESS,\n        "iss": TOKEN_ISSUER,\n        "iat": int(now.timestamp()),\n        "exp": int(expires_at.timestamp()),\n    }\n\n    return jwt.encode(\n        claims,\n        settings.secret_key,\n        algorithm=ALGORITHM,\n    )\n\n\ndef decode_access_token(token: str) -> AccessTokenPayload:\n    """Decode and validate a signed JWT access token."""\n\n    try:\n        payload = jwt.decode(\n            token,\n            settings.secret_key,\n            algorithms=[ALGORITHM],\n            issuer=TOKEN_ISSUER,\n        )\n    except JWTError as exc:\n        raise InvalidTokenError("Token geçersiz veya süresi dolmuş.") from exc\n\n    subject = payload.get("sub")\n    role = payload.get("role")\n    token_type = payload.get("type")\n    business_id = payload.get("business_id")\n    issued_at_timestamp = payload.get("iat")\n    expires_at_timestamp = payload.get("exp")\n\n    if not isinstance(subject, str) or not subject:\n        raise InvalidTokenError("Token subject bilgisi geçersiz.")\n\n    if not isinstance(role, str) or not is_valid_role(role):\n        raise InvalidTokenError("Token rol bilgisi geçersiz.")\n\n    if token_type != TOKEN_TYPE_ACCESS:\n        raise InvalidTokenError("Token tipi geçersiz.")\n\n    if business_id is not None and not isinstance(business_id, int):\n        raise InvalidTokenError("Token işletme bilgisi geçersiz.")\n\n    if not isinstance(issued_at_timestamp, int):\n        raise InvalidTokenError("Token oluşturma zamanı geçersiz.")\n\n    if not isinstance(expires_at_timestamp, int):\n        raise InvalidTokenError("Token son kullanma zamanı geçersiz.")\n\n    return AccessTokenPayload(\n        subject=subject,\n        role=role,\n        business_id=business_id,\n        issued_at=datetime.fromtimestamp(\n            issued_at_timestamp,\n            tz=timezone.utc,\n        ),\n        expires_at=datetime.fromtimestamp(\n            expires_at_timestamp,\n            tz=timezone.utc,\n        ),\n    )\n', 'backend/app/schemas/auth.py': 'from __future__ import annotations\n\nfrom pydantic import BaseModel, Field\n\n\nclass LoginRequest(BaseModel):\n    """Login request payload."""\n\n    username: str = Field(min_length=3, max_length=100)\n    password: str = Field(min_length=1, max_length=255)\n\n\nclass TokenResponse(BaseModel):\n    """Successful authentication response."""\n\n    access_token: str\n    token_type: str = "bearer"\n    expires_in_minutes: int\n\n\nclass TokenPayloadResponse(BaseModel):\n    """Debug-safe token payload response."""\n\n    subject: str\n    role: str\n    business_id: int | None\n    issued_at: str\n    expires_at: str\n', 'backend/app/commands/check_token_security.py': 'from __future__ import annotations\n\nfrom datetime import timedelta\n\nfrom app.core.tokens import (\n    InvalidTokenError,\n    create_access_token,\n    decode_access_token,\n)\n\n\ndef check_valid_access_token() -> None:\n    """Create and decode a valid token."""\n\n    token = create_access_token(\n        subject="1",\n        role="super_admin",\n        business_id=None,\n        expires_delta=timedelta(minutes=15),\n    )\n\n    payload = decode_access_token(token)\n\n    if payload.subject != "1":\n        raise RuntimeError("Token subject hatalı.")\n\n    if payload.role != "super_admin":\n        raise RuntimeError("Token rol bilgisi hatalı.")\n\n    if payload.business_id is not None:\n        raise RuntimeError("Token business_id bilgisi hatalı.")\n\n    print("Geçerli access token kontrolü başarılı.")\n\n\ndef check_business_access_token() -> None:\n    """Create and decode a business scoped token."""\n\n    token = create_access_token(\n        subject="10",\n        role="staff",\n        business_id=1,\n        expires_delta=timedelta(minutes=15),\n    )\n\n    payload = decode_access_token(token)\n\n    if payload.subject != "10":\n        raise RuntimeError("Personel token subject hatalı.")\n\n    if payload.role != "staff":\n        raise RuntimeError("Personel token rol bilgisi hatalı.")\n\n    if payload.business_id != 1:\n        raise RuntimeError("Personel token business_id bilgisi hatalı.")\n\n    print("İşletme kapsamlı access token kontrolü başarılı.")\n\n\ndef check_invalid_role_rejected() -> None:\n    """Invalid roles must not produce tokens."""\n\n    try:\n        create_access_token(\n            subject="1",\n            role="invalid_role",\n            business_id=None,\n            expires_delta=timedelta(minutes=15),\n        )\n    except ValueError:\n        print("Geçersiz rol reddetme kontrolü başarılı.")\n        return\n\n    raise RuntimeError("Geçersiz rol ile token üretildi.")\n\n\ndef check_expired_token_rejected() -> None:\n    """Expired tokens must be rejected."""\n\n    token = create_access_token(\n        subject="1",\n        role="super_admin",\n        business_id=None,\n        expires_delta=timedelta(seconds=-1),\n    )\n\n    try:\n        decode_access_token(token)\n    except InvalidTokenError:\n        print("Süresi dolmuş token reddetme kontrolü başarılı.")\n        return\n\n    raise RuntimeError("Süresi dolmuş token kabul edildi.")\n\n\ndef main() -> None:\n    """Run all JWT token checks."""\n\n    check_valid_access_token()\n    check_business_access_token()\n    check_invalid_role_rejected()\n    check_expired_token_rejected()\n    print("Token güvenlik temel kontrolü başarılı.")\n\n\nif __name__ == "__main__":\n    main()\n', 'backend/tests/test_tokens.py': 'from datetime import timedelta\n\nimport pytest\n\nfrom app.core.tokens import (\n    InvalidTokenError,\n    create_access_token,\n    decode_access_token,\n)\n\n\ndef test_create_and_decode_super_admin_access_token() -> None:\n    token = create_access_token(\n        subject="1",\n        role="super_admin",\n        business_id=None,\n        expires_delta=timedelta(minutes=15),\n    )\n\n    payload = decode_access_token(token)\n\n    assert payload.subject == "1"\n    assert payload.role == "super_admin"\n    assert payload.business_id is None\n\n\ndef test_create_and_decode_staff_access_token() -> None:\n    token = create_access_token(\n        subject="15",\n        role="staff",\n        business_id=2,\n        expires_delta=timedelta(minutes=15),\n    )\n\n    payload = decode_access_token(token)\n\n    assert payload.subject == "15"\n    assert payload.role == "staff"\n    assert payload.business_id == 2\n\n\ndef test_create_access_token_rejects_invalid_role() -> None:\n    with pytest.raises(ValueError):\n        create_access_token(\n            subject="1",\n            role="invalid_role",\n            business_id=None,\n            expires_delta=timedelta(minutes=15),\n        )\n\n\ndef test_decode_access_token_rejects_expired_token() -> None:\n    token = create_access_token(\n        subject="1",\n        role="super_admin",\n        business_id=None,\n        expires_delta=timedelta(seconds=-1),\n    )\n\n    with pytest.raises(InvalidTokenError):\n        decode_access_token(token)\n\n\ndef test_decode_access_token_rejects_invalid_token() -> None:\n    with pytest.raises(InvalidTokenError):\n        decode_access_token("not-a-valid-token")\n'}


def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def compile_files() -> None:
    for relative_path in FILES:
        if relative_path.endswith(".py"):
            py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("Python syntax kontrolu basarili.")


def main() -> None:
    print("Missio ADIM 5B JWT token temeli olusturuluyor.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)

    compile_files()

    print("")
    print("Tamamlandi.")


if __name__ == "__main__":
    main()
